import React, { useEffect, useState } from "react";
import axios from "axios";
import { Line, Bar } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Tooltip,
  Legend,
  Filler,
} from "chart.js";

// Registramos los componentes de ChartJS necesarios, incluyendo Filler para el área bajo la línea
ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Tooltip,
  Legend,
  Filler
);

const API_URL = process.env.REACT_APP_API_URL || "http://localhost:5000";

export default function Reportes() {
  const [ventasDia, setVentasDia] = useState([]);
  const [ventasMes, setVentasMes] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    cargarDatos();
  }, []);

  const cargarDatos = async () => {
    try {
      setLoading(true);
      // Peticiones paralelas para mayor velocidad
      const [resDia, resMes] = await Promise.all([
        axios.get(`${API_URL}/api/reportes/ventas/dia`),
        axios.get(`${API_URL}/api/reportes/ventas/mes`)
      ]);
      
      setVentasDia(resDia.data);
      setVentasMes(resMes.data);
    } catch (error) {
      console.error("❌ Error al cargar reportes:", error);
    } finally {
      setLoading(false);
    }
  };

  /* ================= KPI (Cálculos) ================= */
  // Nos aseguramos de convertir a Number porque Postgres puede devolver strings para SUM
  const totalIngresos = ventasDia.reduce((acc, v) => acc + Number(v.TotalIngresos || 0), 0);
  const totalVentas = ventasDia.reduce((acc, v) => acc + Number(v.TotalVentas || 0), 0);
  const promedio = totalVentas ? (totalIngresos / totalVentas).toFixed(2) : 0;

  /* ================= CONFIGURACIÓN DE GRÁFICAS ================= */

  const ingresosPorDia = {
    labels: ventasDia.map(v => v.Fecha),
    datasets: [
      {
        label: "Ingresos diarios ($)",
        data: ventasDia.map(v => Number(v.TotalIngresos)),
        borderColor: "rgba(75, 192, 192, 1)",
        backgroundColor: "rgba(75, 192, 192, 0.2)",
        borderWidth: 3,
        fill: true,
        tension: 0.3, // Curvatura de la línea
      },
    ],
  };

  const ingresosPorMes = {
    labels: ventasMes.map(v => `${v.Mes}/${v.Año}`),
    datasets: [
      {
        label: "Ingresos mensuales ($)",
        data: ventasMes.map(v => Number(v.TotalIngresos)),
        backgroundColor: "rgba(54, 162, 235, 0.7)",
        borderRadius: 5,
      },
    ],
  };

  const ventasPorMesCount = {
    labels: ventasMes.map(v => `${v.Mes}/${v.Año}`),
    datasets: [
      {
        label: "Cantidad de ventas",
        data: ventasMes.map(v => Number(v.TotalVentas)),
        backgroundColor: "rgba(255, 159, 64, 0.7)",
        borderRadius: 5,
      },
    ],
  };

  if (loading) return <div className="text-center mt-5"><div className="spinner-border text-primary"></div><p>Cargando estadísticas...</p></div>;

  return (
    <div className="container mt-4 pb-5">
      <h2 className="fw-bold mb-4 text-dark">📊 Panel de Reportes y Estadísticas</h2>

      {/* Tarjetas KPI */}
      <div className="row mb-4 g-3">
        <div className="col-md-4">
          <div className="card shadow-sm border-0 border-start border-success border-5 p-3">
            <h6 className="text-muted">Total Ingresos Históricos</h6>
            <h3 className="text-success fw-bold">${totalIngresos.toLocaleString('en-US', { minimumFractionDigits: 2 })}</h3>
          </div>
        </div>

        <div className="col-md-4">
          <div className="card shadow-sm border-0 border-start border-primary border-5 p-3">
            <h6 className="text-muted">Total Transacciones</h6>
            <h3 className="text-primary fw-bold">{totalVentas} ventas</h3>
          </div>
        </div>

        <div className="col-md-4">
          <div className="card shadow-sm border-0 border-start border-info border-5 p-3">
            <h6 className="text-muted">Ticket Promedio</h6>
            <h3 className="text-info fw-bold">${promedio}</h3>
          </div>
        </div>
      </div>

      {/* Sección de Gráficas */}
      <div className="row">
        <div className="col-12 mb-4">
          <div className="card shadow-sm p-4">
            <h5 className="fw-bold mb-3">📈 Evolución de Ingresos Diarios</h5>
            <div style={{ height: "350px" }}>
              <Line data={ingresosPorDia} options={{ maintainAspectRatio: false }} />
            </div>
          </div>
        </div>

        <div className="col-md-6 mb-4">
          <div className="card shadow-sm p-4">
            <h5 className="fw-bold mb-3">📊 Comparativa de Ingresos Mensuales</h5>
            <div style={{ height: "300px" }}>
              <Bar data={ingresosPorMes} options={{ maintainAspectRatio: false }} />
            </div>
          </div>
        </div>

        <div className="col-md-6 mb-4">
          <div className="card shadow-sm p-4">
            <h5 className="fw-bold mb-3">📦 Volumen de Ventas Mensuales</h5>
            <div style={{ height: "300px" }}>
              <Bar data={ventasPorMesCount} options={{ maintainAspectRatio: false }} />
            </div>
          </div>
        </div>
      </div>a
    </div>
  );
}
